echo '
<div style="margin: 15px 0; text-align: center;">
  <input type="text" id="searchBerita" placeholder="Cari Judul Berita..."
         style="padding: 8px 12px; width: 300px; border: 1px solid #ccc; border-radius: 6px; font-size: 14px;" 
         onkeyup="autoSearchBerita()" />
</div>

<div id="resetSearchContainer" style="display: none; margin-top: 10px; text-align: center;">
  <button onclick="resetBeritaSearch()" 
          style="padding: 8px 16px; background-color: #dc3545; color: white; border: none; border-radius: 6px; cursor: pointer;">
    🔄 Batalkan Cari / Kembali
  </button>
</div>

<script>
let beritaTimeout;

function autoSearchBerita() {
  clearTimeout(beritaTimeout);
  beritaTimeout = setTimeout(function() {
    const keyword = document.getElementById("searchBerita").value.trim();
    if (keyword !== "") {
      window.location.href = "newsmain_list.php?q=(Title~contains~" + encodeURIComponent(keyword) + ")";
    }
  }, 800);
}

function resetBeritaSearch() {
  window.location.href = "newsmain_list.php";
}

// Tampilkan tombol reset jika ada parameter ?q=
window.addEventListener("DOMContentLoaded", function() {
  const params = new URLSearchParams(window.location.search);
  if (params.has("q")) {
    document.getElementById("resetSearchContainer").style.display = "block";
  }
});
</script>
';
